/**
 * @param {bigint} l
 * @param {bigint} r
 * @param {string} directions
 * @return {number}
 */
function solve(l, r, directions) {
    let count = 0;

    for (let x = l; x <= r; x++) {
        // 1. Format x to 16-bit string with leading zeros
        const xStr = x.toString().padStart(16, '0');

        // 2. Create the 4x4 grid
        const grid = Array(4).fill(0).map(() => Array(4).fill(0));
        for (let i = 0; i < 16; i++) {
            const digit = parseInt(xStr[i]);
            const row = Math.floor(i / 4);
            const col = i % 4;
            grid[row][col] = digit;
        }

        // 3. Simulate the path traversal
        let row = 0;
        let col = 0;
        const sequence = [];

        // Start at (0, 0)
        sequence.push(grid[row][col]);

        // Apply 6 directions
        for (let i = 0; i < 6; i++) {
            const move = directions[i];
            if (move === 'D') {
                row += 1;
            } else if (move === 'R') {
                col += 1;
            }

            // Boundary checks are implicitly handled by the problem context 
            // (though the path description implies the moves are taken sequentially 
            // regardless of boundaries for the sequence generation, but we must ensure 
            // we are reading a valid cell).
            // The problem statement implies the path is always valid for 7 steps (1 start + 6 moves).
            // Given the grid is 4x4, any move outside [0, 3] should theoretically not happen 
            // if the input guarantees a sensible path for 6 moves, but we must ensure we access grid[row][col].
            // Since we are only recording 7 elements, we just track the position.

            if (row >= 0 && row < 4 && col >= 0 && col < 4) {
                sequence.push(grid[row][col]);
            }
        }

        // 4. Check if the sequence is non-decreasing
        let isGood = true;
        for (let i = 1; i < sequence.length; i++) {
            if (sequence[i] < sequence[i - 1]) {
                isGood = false;
                break;
            }
        }

        if (isGood) {
            count++;
        }
    }

    return count;
}

